function createRenderer() {
  function clamp(x) { return Math.max(0, Math.min(1, x)); }
  function easeOut(x) { x = clamp(x); return 1 - Math.pow(1 - x, 3); }
  function easeInOut(x) { x = clamp(x); return x < 0.5 ? 4 * x * x * x : 1 - Math.pow(-2 * x + 2, 3) / 2; }
  function rr(ctx, x, y, w, h, r) { ctx.beginPath(); ctx.moveTo(x + r, y); ctx.lineTo(x + w - r, y); ctx.quadraticCurveTo(x + w, y, x + w, y + r); ctx.lineTo(x + w, y + h - r); ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h); ctx.lineTo(x + r, y + h); ctx.quadraticCurveTo(x, y + h, x, y + h - r); ctx.lineTo(x, y + r); ctx.quadraticCurveTo(x, y, x + r, y); ctx.closePath(); }
  function render(t, context) {
    var ctx = context.mainContext;
    var W = context.width;
    var H = context.height;
    var intro = easeOut(t / 1.35);
    var reveal = easeInOut((t - 0.8) / 2.4);
    var settle = easeOut((t - 3.4) / 1.1);
    var pulse = 0.5 + 0.5 * Math.sin(t * 2.2);

    var bg = ctx.createLinearGradient(0, 0, W, H);
    bg.addColorStop(0, '#050914');
    bg.addColorStop(0.52, '#0B1D34');
    bg.addColorStop(1, '#102116');
    ctx.fillStyle = bg;
    ctx.fillRect(0, 0, W, H);

    drawGrid(ctx, W, H, t);
    drawLightSweep(ctx, W, H, t, reveal);
    drawMark(ctx, W, H, t, intro, reveal, pulse);
    drawWordmark(ctx, W, H, t, intro, reveal, settle);
    drawPipeline(ctx, W, H, settle);
    drawProgress(ctx, W, H, t);
  }

  function drawGrid(ctx, W, H, t) {
    ctx.save();
    ctx.globalAlpha = 0.11;
    ctx.strokeStyle = '#DFF6FF';
    ctx.lineWidth = 1;
    for (var x = -100; x < W + 100; x += 80) { ctx.beginPath(); ctx.moveTo(x + (t * 18) % 80, 0); ctx.lineTo(x - 240 + (t * 18) % 80, H); ctx.stroke(); }
    for (var y = 0; y < H; y += 80) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke(); }
    ctx.restore();
  }

  function drawLightSweep(ctx, W, H, t, reveal) {
    ctx.save();
    var x = -W * 0.3 + reveal * W * 1.6;
    var g = ctx.createLinearGradient(x - 220, 0, x + 220, H);
    g.addColorStop(0, 'rgba(0,212,255,0)');
    g.addColorStop(0.5, 'rgba(255,255,255,0.2)');
    g.addColorStop(1, 'rgba(242,170,76,0)');
    ctx.fillStyle = g;
    ctx.translate(x, H / 2);
    ctx.rotate(-0.32);
    ctx.fillRect(-90, -H, 180, H * 2);
    ctx.restore();
  }

  function drawMark(ctx, W, H, t, intro, reveal, pulse) {
    var cx = W * 0.34;
    var cy = H * 0.48;
    var size = 300;
    ctx.save();
    ctx.translate(cx, cy);
    ctx.rotate((-8 + reveal * 8 + Math.sin(t * 1.2) * 0.8) * Math.PI / 180);
    ctx.scale(0.78 + intro * 0.22, 0.78 + intro * 0.22);
    ctx.globalAlpha = intro;
    ctx.shadowColor = 'rgba(0, 212, 255, 0.45)';
    ctx.shadowBlur = 44 + pulse * 18;
    rr(ctx, -size / 2, -size / 2, size, size, 66);
    ctx.fillStyle = '#071019';
    ctx.fill();
    ctx.lineWidth = 20;
    var border = ctx.createLinearGradient(-size / 2, -size / 2, size / 2, size / 2);
    border.addColorStop(0, '#00D4FF');
    border.addColorStop(0.5, '#7BD88F');
    border.addColorStop(1, '#F2AA4C');
    ctx.strokeStyle = border;
    ctx.stroke();
    ctx.shadowBlur = 0;
    ctx.fillStyle = border;
    ctx.beginPath();
    ctx.moveTo(-36, -70);
    ctx.lineTo(84, 0);
    ctx.lineTo(-36, 70);
    ctx.closePath();
    ctx.fill();
    ctx.strokeStyle = 'rgba(223, 246, 255, 0.88)';
    ctx.lineWidth = 16;
    ctx.lineCap = 'round';
    ctx.beginPath();
    ctx.moveTo(-94, 94);
    ctx.lineTo(96, 94);
    ctx.stroke();
    ctx.restore();
  }

  function drawWordmark(ctx, W, H, t, intro, reveal, settle) {
    ctx.save();
    ctx.translate(W * 0.49 + (1 - reveal) * 80, H * 0.48);
    ctx.globalAlpha = reveal;
    ctx.textAlign = 'left';
    ctx.textBaseline = 'middle';
    ctx.font = '900 168px Arial, sans-serif';
    var text = ctx.createLinearGradient(0, -90, 460, 80);
    text.addColorStop(0, '#FFFFFF');
    text.addColorStop(0.6, '#D7E6F4');
    text.addColorStop(1, '#90AFC8');
    ctx.fillStyle = text;
    ctx.fillText('ui2v', 0, -28);
    ctx.font = '700 32px Arial, sans-serif';
    ctx.fillStyle = '#9CB7CC';
    ctx.fillText('JSON timeline to browser-rendered MP4', 8, 78);
    ctx.globalAlpha = settle;
    ctx.font = '800 24px Arial, sans-serif';
    ctx.fillStyle = '#7BD88F';
    ctx.fillText('validate  preview  render', 10, 132);
    ctx.restore();
  }

  function drawPipeline(ctx, W, H, p) {
    var steps = ['JSON', 'Runtime', 'Canvas', 'WebCodecs', 'MP4'];
    ctx.save();
    ctx.globalAlpha = p;
    ctx.font = '800 20px Arial, sans-serif';
    ctx.textAlign = 'center';
    for (var i = 0; i < steps.length; i++) {
      var x = W * 0.5 - 340 + i * 170;
      var y = H * 0.78;
      ctx.fillStyle = 'rgba(5, 9, 20, 0.72)';
      ctx.strokeStyle = i === steps.length - 1 ? '#F2AA4C' : '#00D4FF';
      rr(ctx, x - 64, y - 34, 128, 68, 16);
      ctx.fill();
      ctx.stroke();
      ctx.fillStyle = '#EEF6FF';
      ctx.fillText(steps[i], x, y + 7);
      if (i < steps.length - 1) {
        ctx.strokeStyle = 'rgba(255,255,255,0.34)';
        ctx.beginPath(); ctx.moveTo(x + 70, y); ctx.lineTo(x + 98, y); ctx.stroke();
      }
    }
    ctx.restore();
  }

  function drawProgress(ctx, W, H, t) {
    var p = clamp(t / 6);
    ctx.fillStyle = 'rgba(255,255,255,0.12)';
    rr(ctx, 160, H - 78, W - 320, 12, 6);
    ctx.fill();
    var g = ctx.createLinearGradient(160, 0, W - 160, 0);
    g.addColorStop(0, '#00D4FF');
    g.addColorStop(0.54, '#7BD88F');
    g.addColorStop(1, '#F2AA4C');
    ctx.fillStyle = g;
    rr(ctx, 160, H - 78, (W - 320) * p, 12, 6);
    ctx.fill();
  }

  return { render: render };
}
